using System.ComponentModel;
using System.Text;
using System.Text.RegularExpressions;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using OpenAI;

// --- Configuration ---
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable to run this agent.");

var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini-2024-07-18";

// --- Build the IChatClient via MEAI ---
IChatClient chatClient = new OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsIChatClient();

// --- Create tool instances ---
var webSearch = new WebSearchTool();
var noteTaking = new NoteTakingTool();

var tools = new AITool[]
{
    AIFunctionFactory.Create(webSearch.SearchWeb, nameof(webSearch.SearchWeb),
        "Search the web for information about a topic. Returns relevant results with titles and snippets."),
    AIFunctionFactory.Create(webSearch.FetchWebPage, nameof(webSearch.FetchWebPage),
        "Fetch the text content of a specific web page URL."),
    AIFunctionFactory.Create(noteTaking.SaveNote, nameof(noteTaking.SaveNote),
        "Save a research note with a title and content. Use this to record important findings."),
    AIFunctionFactory.Create(noteTaking.GetAllNotes, nameof(noteTaking.GetAllNotes),
        "Retrieve all saved research notes to review findings before writing a summary."),
};

// --- Create the agent ---
var agent = new ChatClientAgent(
    chatClient,
    instructions: """
        You are a research agent. Your job is to thoroughly research a topic by:
        1. Searching the web for relevant information using the SearchWeb tool.
        2. Fetching specific web pages for detailed content when needed with FetchWebPage.
        3. Taking notes on key findings using the SaveNote tool.
        4. After gathering enough information, calling GetAllNotes and producing a comprehensive summary.

        Always save important findings as notes before producing your final summary.
        When done, present a well-structured summary with key points.
        """,
    name: "ResearchAgent",
    description: "An agent that researches topics by searching the web and summarizing findings.",
    tools: tools);

// --- Get the research topic ---
Console.Write("Enter a topic to research: ");
var topic = Console.ReadLine()?.Trim();

if (string.IsNullOrEmpty(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine($"\n🔍 Researching: {topic}\n");

// --- Run the agent with streaming ---
var runOptions = new ChatClientAgentRunOptions(
    new ChatOptions
    {
        Temperature = 0f,
        MaxOutputTokens = 2048,
    });

await foreach (var update in agent.RunStreamingAsync(
    $"Research the following topic and provide a comprehensive summary: {topic}",
    session: null,
    runOptions))
{
    Console.Write(update.Text);
}

Console.WriteLine("\n\n✅ Research complete.");

// ──────────────────────────────────────────────
//  Tool implementations
// ──────────────────────────────────────────────

/// <summary>Provides web search and page-fetching capabilities.</summary>
sealed class WebSearchTool
{
    private static readonly HttpClient s_http = new()
    {
        DefaultRequestHeaders = { { "User-Agent", "ResearchAgent/1.0" } },
        Timeout = TimeSpan.FromSeconds(15),
    };

    public async Task<string> SearchWeb(
        [Description("The search query to look up")] string query)
    {
        var encodedQuery = Uri.EscapeDataString(query);
        var url = $"https://lite.duckduckgo.com/lite/?q={encodedQuery}";

        Console.WriteLine($"  🌐 Searching: \"{query}\"");

        try
        {
            var html = await s_http.GetStringAsync(url);
            var text = StripHtml(html);

            return string.IsNullOrWhiteSpace(text)
                ? "No results found."
                : Truncate(text, 4000);
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}";
        }
    }

    public async Task<string> FetchWebPage(
        [Description("The full URL of the web page to fetch")] string url)
    {
        Console.WriteLine($"  📄 Fetching: {url}");

        try
        {
            var html = await s_http.GetStringAsync(url);

            // Remove scripts and styles before stripping tags
            html = Regex.Replace(html, @"<script[^>]*>.*?</script>", "", RegexOptions.Singleline);
            html = Regex.Replace(html, @"<style[^>]*>.*?</style>", "", RegexOptions.Singleline);

            var text = StripHtml(html);

            return string.IsNullOrWhiteSpace(text)
                ? "Could not extract content from the page."
                : Truncate(text, 4000);
        }
        catch (Exception ex)
        {
            return $"Fetch failed: {ex.Message}";
        }
    }

    private static string StripHtml(string html)
    {
        var text = Regex.Replace(html, "<[^>]+>", " ");
        return Regex.Replace(text, @"\s+", " ").Trim();
    }

    private static string Truncate(string text, int maxLength) =>
        text.Length <= maxLength ? text : text[..maxLength] + "…";
}

/// <summary>Provides in-memory note-taking capabilities for the agent.</summary>
sealed class NoteTakingTool
{
    private readonly List<(string Title, string Content)> _notes = [];

    public string SaveNote(
        [Description("A short title for the note")] string title,
        [Description("The detailed content of the note")] string content)
    {
        _notes.Add((title, content));
        Console.WriteLine($"  📝 Note saved: \"{title}\"");
        return $"Note #{_notes.Count} saved: '{title}'";
    }

    public string GetAllNotes()
    {
        if (_notes.Count == 0)
            return "No notes saved yet.";

        var sb = new StringBuilder();
        for (int i = 0; i < _notes.Count; i++)
        {
            sb.AppendLine($"--- Note #{i + 1}: {_notes[i].Title} ---");
            sb.AppendLine(_notes[i].Content);
            sb.AppendLine();
        }

        return sb.ToString();
    }
}

